class Solution(object):
    def totalMoney(self, n):
        weeks = n // 7
        days = n % 7
        total = weeks * (1 + 2 + 3 + 4 + 5 + 6 + 7) + weeks * (weeks - 1) // 2 * 7
        for i in range(days):
            total += weeks + i + 1
        return total
